import { Icons } from "@repo/ui/components/icons";
import {
  Activity,
  ArrowUp,
  Boxes,
  Briefcase,
  ChevronsUpDown,
  HelpCircle,
  MessageSquare,
  Plug,
  Search,
  Settings,
} from "lucide-react";
import { ProductDemoMailbox } from "./product-demo-mailbox";

export function ProductDemo() {
  return (
    <div className="dark overflow-hidden rounded-2xl shadow-2xl">
      <div className="flex h-[540px] bg-sidebar md:h-[580px] lg:h-[620px]">
        {/* Sidebar — hidden below lg */}
        <Sidebar />
        {/* Right column */}
        <div className="flex min-h-0 flex-1 flex-col pr-1.5 pb-1.5 md:pr-2 md:pb-2">
          <Header />
          {/* Inset card */}
          <div className="flex flex-1 overflow-hidden rounded-xl bg-background shadow-sm">
            <ProductDemoMailbox />
            <Chat />
          </div>
        </div>
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Sidebar                                                           */
/* ------------------------------------------------------------------ */

const sidebarPrimaryNav = [
  { label: "Explore", icon: MessageSquare, active: true },
  { label: "Entities", icon: Boxes, active: false },
];

const sidebarManageNav = [
  { label: "Events", icon: Activity },
  { label: "Sources", icon: Plug },
  { label: "Jobs", icon: Briefcase },
  { label: "Settings", icon: Settings },
];

function Sidebar() {
  return (
    <div className="hidden w-[14rem] shrink-0 flex-col lg:flex">
      {/* Header */}
      <div className="flex h-14 items-center gap-2 px-4">
        <div className="flex size-6 items-center justify-center rounded-md bg-foreground text-[10px] font-medium text-background">
          LF
        </div>
        <span className="font-medium text-base">Lightfast</span>
        <ChevronsUpDown className="ml-auto size-3.5 opacity-50" />
        <button
          className="flex size-6 items-center justify-center rounded-full hover:bg-muted"
          type="button"
        >
          <Search className="size-3.5" />
        </button>
      </div>

      {/* Primary nav */}
      <div className="flex flex-col gap-0.5 px-2">
        {sidebarPrimaryNav.map((item) => (
          <div
            className={`flex items-center gap-2 rounded-xl px-2 py-1.5 text-sm ${
              item.active
                ? "text-foreground"
                : "text-muted-foreground"
            }`}
            key={item.label}
          >
