            Live
          </div>
        </div>

        {/* Search bar */}
        <div className="flex items-center gap-2 border-b border-border/40 px-3 py-2">
          <Search className="size-3.5 text-muted-foreground" />
          <span className="text-sm text-muted-foreground">Search...</span>
        </div>

        {/* Entities tab */}
        <TabsContent value="entities" className="mt-0 flex-1 overflow-y-auto">
          {DEMO_ENTITIES.map((entity) => (
            <div
              className="flex cursor-pointer items-start gap-3 px-3 py-3 transition-colors hover:bg-muted/50"
              key={entity.key}
            >
              <div className="flex min-w-0 flex-1 flex-col gap-1">
                <div className="flex items-center gap-2">
                  <span className="truncate font-medium text-sm">
                    {entity.key}
                  </span>
                  <Badge
                    className="shrink-0 font-normal text-xs"
                    variant="secondary"
                  >
                    {entity.state}
                  </Badge>
                </div>
                <div className="flex items-center gap-2">
                  <Badge className="font-normal text-xs" variant="outline">
                    {entity.category}
                  </Badge>
                  <span className="ml-auto text-xs text-muted-foreground">
                    {entity.time}
                  </span>
                </div>
              </div>
            </div>
          ))}
        </TabsContent>

        {/* Events tab */}
        <TabsContent value="events" className="mt-0 flex-1 overflow-y-auto">
          {DEMO_EVENTS.map((event) => (
            <div
              className="flex cursor-pointer items-center gap-3 px-3 py-3 transition-colors hover:bg-muted/50"
              key={event.title}
            >
              <div className="size-4 shrink-0 rounded bg-muted" />
              <span className="min-w-0 flex-1 truncate font-medium text-sm">
                {event.title}
              </span>
              <Badge
                className="shrink-0 font-normal text-xs"
                variant="secondary"
              >
                {event.label}
              </Badge>
              <span className="shrink-0 text-xs text-muted-foreground">
                {event.time}
              </span>
            </div>
          ))}
        </TabsContent>
      </Tabs>
    </div>
  );
}

